      { "name": "Payment Gateway (External)", "responsibility": "Processes payment authorization and capture", "boundaries": "Third-party dependency; PCI-scoped" },
      { "name": "Database", "responsibility": "Persists shipment, order, and customer data", "boundaries": "Internal; dashboard shows normal query times — likely not the bottleneck" }
