      { "from": "Logistics API", "to": "Payment Gateway", "contract": "HTTP REST — payment details in, authorization out", "coupling_type": "temporal (synchronous call in request path)" },
      { "from": "Logistics API", "to": "Database", "contract": "SQL queries via connection pool", "coupling_type": "temporal (synchronous, but confirmed healthy)" }
    ],
    "data_flow": "Inbound request → DB lookup → sequential or parallel calls to geocoding, carrier rates, and payment gateway → response assembly → return. If external calls are sequential, total latency = sum of all three. If parallel, total latency = max of the three. The 1800ms P99 suggests either one service is very slow or sequential calls are compounding degradation across multiple services.",
    "patterns_used": []
  },

  "domain_model": {
    "bounded_contexts": [
      { "name": "Shipment Orchestration", "classification": "core", "aggregates": ["Shipment", "Quote"] },
      { "name": "Geocoding", "classification": "generic", "aggregates": [] },
      { "name": "Carrier Rating", "classification": "supporting", "aggregates": [] },
      { "name": "Payment", "classification": "supporting", "aggregates": [] }
