      { "upstream": "Geocoding Service", "downstream": "Logistics API", "relationship": "Conformist — API consumes upstream model directly, likely no ACL" },
      { "upstream": "Carrier Rates API", "downstream": "Logistics API", "relationship": "Conformist — likely no ACL, direct coupling to upstream response format" },
      { "upstream": "Payment Gateway", "downstream": "Logistics API", "relationship": "Conformist or Customer-Supplier depending on contract" }
    ]
