  "trade_offs": [
    { "decision": "Synchronous external API calls in the request path", "gains": "Simple request model, easy to reason about, consistent data", "sacrifices": "Latency is bounded by slowest external call; no isolation from upstream degradation; P99 is at the mercy of third parties", "alternatives_considered": ["Async processing with webhooks/callbacks", "Caching geocoding results", "Circuit breakers with fallback responses"] },
    { "decision": "No circuit breakers or timeout enforcement (suspected)", "gains": "Simpler code, no partial failure handling needed", "sacrifices": "Cascading latency from degraded upstream; no graceful degradation; thread/connection pool starvation under sustained slow responses", "alternatives_considered": ["Circuit breaker pattern (Hystrix/Resilience4j/Polly)", "Aggressive timeouts with retry budget", "Bulkhead isolation per external dependency"] }
